function openHazardForm(item=null){
const form=document.getElementById('hazardForm');
document.getElementById('hazardFormCard').classList.remove('hidden');
form.reset();
hazardOriginalGeojson=item?JSON.parse(JSON.stringify(item.geojson_data)):null;
hazardRedrawPending=false;
if(!item){hazardHiddenId=null;loadAdminHazards();}
form.elements.id.value=item?.id||'';
form.elements.hazard_name.value=item?.hazard_name||'';
setHazardTypeFields(item?.hazard_type||'flood_zone');
form.elements.municipality_id.value=user.role==='subadmin'?user.municipality_id:(item?.municipality_id||'');
form.elements.risk_level.value=item?.risk_level||'low';
form.elements.description.value=item?.description||'';
form.elements.geojson_text.value=item?JSON.stringify(item.geojson_data,null,2):'';
document.getElementById('hazardFormTitle').textContent=item?'Edit hazard':'Add hazard';
document.getElementById('redrawHazardArea')?.classList.toggle('hidden',!item);
document.getElementById('hazardFormError').classList.add('hidden');
const coverage=document.getElementById('hazardCoverage');
if(coverage){coverage.className='hazard-coverage hidden';coverage.replaceChildren();}
setTimeout(()=>adminMap?.invalidateSize(),80);
if(item){previewHazard(item.geojson_data,true);lookupHazardCoverage(item.geojson_data);}else{clearHazardEditHandles();marker?.remove();marker=null;}
}
