function safeZoneIcon(kind='saved'){const colors={saved:'#059669',center:'#2563eb',nearest:'#f59e0b',draft:'#7c3aed'},icons={saved:'<path class="icon-fill" d="M28 9.5 40.5 14v9.2c0 7.7-5 13.6-12.5 17.3-7.5-3.7-12.5-9.6-12.5-17.3V14L28 9.5Z"/><rect class="icon-cut-fill" x="25" y="17" width="6" height="17" rx="1.3"/><rect class="icon-cut-fill" x="19.5" y="22.5" width="17" height="6" rx="1.3"/>',center:'<path class="icon-fill" d="M14 21.5 28 11l14 10.5V40H14V21.5Z"/><path class="icon-cut-fill" d="M19 23h18v3.5H19z"/><rect class="icon-cut-fill" x="25" y="28" width="6" height="11" rx="1"/><rect class="icon-cut-fill" x="22" y="31" width="12" height="4.5" rx="1"/>',nearest:'<path class="icon-fill" d="M27.7 10.5 41 39.5 29.2 34l-9.7 7 8.2-30.5Z"/>',draft:'<circle class="icon-fill" cx="28" cy="25" r="11"/><path class="icon-cut" d="M28 18.5v13M21.5 25h13"/>'},color=colors[kind]||colors.saved,inner=icons[kind]||icons.saved;return L.divIcon({className:`safe-zone-marker safe-zone-marker-${kind}`,iconSize:[50,60],iconAnchor:[25,58],popupAnchor:[0,-50],html:`<svg class="safe-zone-pin-svg" viewBox="0 0 56 66" aria-hidden="true"><ellipse class="safe-zone-pin-shadow" cx="28" cy="61" rx="13" ry="4"/><path class="safe-zone-pin-body" style="--pin-color:${color}" d="M28 2C16.1 2 6.5 11.3 6.5 23.1c0 15.8 21.5 40.9 21.5 40.9s21.5-25.1 21.5-40.9C49.5 11.3 39.9 2 28 2Z"/><circle class="safe-zone-pin-badge" cx="28" cy="24" r="15.5"/><g class="safe-zone-pin-symbol" style="--pin-color:${color}">${inner}</g></svg>`});}
