function safeZoneMapCard(s,compact=false){const distance=s.distance_km!==undefined?`<span class="safe-zone-distance">${s.distance_km} km away</span>`:'',capacity=s.capacity??'Not specified',coords=`${Number(s.latitude).toFixed(4)}, ${Number(s.longitude).toFixed(4)}`;if(compact)return `<article class="safe-zone-tooltip-card"><strong>${escapeText(s.safezone_name)}</strong><span>${escapeText(s.municipality_name||'Municipality unavailable')}</span></article>`;return `<article class="safe-zone-popup-card"><div class="safe-zone-card-accent"></div><header><span class="safe-zone-card-icon">✓</span><div><span class="safe-zone-card-kicker">Designated safe zone</span><h3>${escapeText(s.safezone_name)}</h3></div></header><section class="safe-zone-card-address"><span>Address</span><p>${escapeText(s.address||'No address provided')}</p></section><div class="safe-zone-card-meta"><span>${escapeText(s.municipality_name||'Municipality unavailable')}</span>${distance}</div><dl><div class="safe-zone-card-primary-stat"><dt>Capacity</dt><dd>${capacity}</dd></div><div><dt>Coordinates</dt><dd>${coords}</dd></div></dl></article>`;}
function normalizeSafeZonePlace(value){return String(value||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/\b(brgy|barangay|city of|municipality of|pob\.?|poblacion)\b/g,' ').replace(/\bgen\.\s*/g,'general ').replace(/[^a-z0-9]+/g,' ').trim();}
async function safeZonePsgcCode(cityName){if(!safeZonePsgcPlaces){const response=await fetch('https://psgc.gitlab.io/api/provinces/042100000/cities-municipalities.json');if(!response.ok)throw new Error('Unable to load Cavite cities and municipalities');safeZonePsgcPlaces=await response.json();}const target=normalizeSafeZonePlace(cityName),places=safeZonePsgcPlaces||[];return places.find(place=>normalizeSafeZonePlace(place.name)===target)?.code||places.find(place=>normalizeSafeZonePlace(place.name).includes(target)||target.includes(normalizeSafeZonePlace(place.name)))?.code||'';}
function selectedSafeZoneCity(form){return form.elements.municipality_id.selectedOptions[0]?.textContent.trim()||'';}
function composeSafeZoneAddress(form){const exact=form.elements.exact_address?.value.trim()||'',barangay=form.elements.barangay?.value.trim()||'',city=selectedSafeZoneCity(form),parts=[exact,barangay?`Barangay ${barangay}`:'',city,'Cavite','Philippines'].filter(Boolean);return parts.join(', ');}
function safeZoneAddressQueries(form){const exact=form.elements.exact_address?.value.trim()||'',barangay=form.elements.barangay?.value.trim()||'',city=selectedSafeZoneCity(form),brgy=barangay?`Barangay ${barangay}`:'';return [[exact,brgy,city,'Cavite','Philippines'],[exact,city,'Cavite','Philippines'],[brgy,city,'Cavite','Philippines'],[city,'Cavite','Philippines']].map(parts=>parts.filter(Boolean).join(', ')).filter((query,index,items)=>query&&items.indexOf(query)===index);}
async function loadSafeZoneBarangays(){const form=document.getElementById('safeZoneForm');if(!form?.elements.barangay)return[];const select=form.elements.barangay,city=selectedSafeZoneCity(form);select.disabled=true;select.innerHTML='<option value="">Loading barangays...</option>';try{const code=await safeZonePsgcCode(city);if(!code)throw new Error('City or municipality was not found in PSGC');let rows=safeZoneBarangayCache.get(code);if(!rows){const response=await fetch(`https://psgc.gitlab.io/api/cities-municipalities/${code}/barangays.json`);if(!response.ok)throw new Error('Unable to load barangays');rows=await response.json();safeZoneBarangayCache.set(code,rows);}select.innerHTML='<option value="">Select barangay</option>';rows.forEach(item=>select.add(new Option(item.name,item.name)));select.disabled=false;return rows;}catch(error){select.innerHTML='<option value="">Barangays unavailable</option>';toast(error.message);return[];}}
async function photonSafeZoneFeature(query){const response=await fetch(`https://photon.komoot.io/api/?q=${encodeURIComponent(query)}&limit=8&lat=${Config.MAP_CENTER[0]}&lon=${Config.MAP_CENTER[1]}`,{headers:{Accept:'application/json'}}),data=response.ok?await response.json():null,bounds=Config.MAP_BOUNDS;return (data?.features||[]).find(feature=>{const lat=Number(feature.geometry.coordinates[1]),lng=Number(feature.geometry.coordinates[0]);return lat>=bounds[0][0]&&lat<=bounds[1][0]&&lng>=bounds[0][1]&&lng<=bounds[1][1];})||null;}
function matchSafeZoneOption(select,text){const normalized=normalizeSafeZonePlace(text),parts=String(text||'').split(',').map(normalizeSafeZonePlace).filter(Boolean);return [...select.options].find(option=>{if(!option.value)return false;const label=normalizeSafeZonePlace(option.textContent);return label&&((normalized.includes(label)||label.includes(normalized))||parts.some(part=>part.includes(label)||label.includes(part)));})||null;}
function matchSafeZoneBarangay(rows,text){const normalized=normalizeSafeZonePlace(text),parts=String(text||'').split(',').map(normalizeSafeZonePlace).filter(Boolean);return rows.find(item=>{const name=normalizeSafeZonePlace(item.name);return name.length>1&&((normalized.includes(name)||name.includes(normalized))||parts.some(part=>part.includes(name)||name.includes(part)));})||null;}
async function inferSafeZoneAddressFields(showToast=false){const form=document.getElementById('safeZoneForm');if(!form)return;const exact=form.elements.exact_address?.value.trim()||'';if(!exact)return;try{const typedCity=matchSafeZoneOption(form.elements.municipality_id,exact);let feature=null;if(exact.length>2)feature=await photonSafeZoneFeature(`${exact}, Cavite, Philippines`);const props=feature?.properties||{},searchText=[exact,props.name,props.street,props.locality,props.district,props.city,props.county,props.state].filter(Boolean).join(' '),cityOption=typedCity||matchSafeZoneOption(form.elements.municipality_id,searchText);let rows=[];if(cityOption&&form.elements.municipality_id.value!==cityOption.value){form.elements.municipality_id.value=cityOption.value;form.elements.latitude.value='';form.elements.longitude.value='';rows=await loadSafeZoneBarangays();}else if(form.elements.municipality_id.value){rows=await loadSafeZoneBarangays();}const barangaySelect=form.elements.barangay;if(rows.length&&barangaySelect){const barangay=matchSafeZoneBarangay(rows,searchText);if(barangay)barangaySelect.value=barangay.name;}if(form.elements.municipality_id.value&&form.elements.barangay.value)geocodeSafeZoneAddress(false);else if(showToast)toast('City detected. Select barangay if it was not found automatically.');}catch(error){if(showToast)toast(error.message);}}
async function photonSafeZoneSearch(query){const response=await fetch(`https://photon.komoot.io/api/?q=${encodeURIComponent(query)}&limit=5&lat=${Config.MAP_CENTER[0]}&lon=${Config.MAP_CENTER[1]}`,{headers:{Accept:'application/json'}}),data=response.ok?await response.json():null,bounds=Config.MAP_BOUNDS;return (data?.features||[]).map(feature=>({lat:Number(feature.geometry.coordinates[1]),lng:Number(feature.geometry.coordinates[0])})).find(point=>point.lat>=bounds[0][0]&&point.lat<=bounds[1][0]&&point.lng>=bounds[0][1]&&point.lng<=bounds[1][1]);}
async function nominatimSafeZoneSearch(query){const viewbox=`${Config.MAP_BOUNDS[0][1]},${Config.MAP_BOUNDS[1][0]},${Config.MAP_BOUNDS[1][1]},${Config.MAP_BOUNDS[0][0]}`,response=await fetch(`https://nominatim.openstreetmap.org/search?format=jsonv2&limit=3&countrycodes=ph&bounded=1&viewbox=${viewbox}&q=${encodeURIComponent(query)}`,{headers:{Accept:'application/json'}}),rows=response.ok?await response.json():[];const first=rows[0];return first?{lat:Number(first.lat),lng:Number(first.lon)}:null;}
async function geocodeSafeZoneAddress(showToast=false){const form=document.getElementById('safeZoneForm');if(!form||!form.elements.barangay.value||!form.elements.municipality_id.value)return;const button=document.getElementById('safeZoneGeocodeBtn');if(button){button.disabled=true;button.textContent='Detecting...';}try{let point=null,matchedQuery='';for(const query of safeZoneAddressQueries(form)){point=await photonSafeZoneSearch(query)||await nominatimSafeZoneSearch(query);if(point){matchedQuery=query;break;}}if(!point)throw new Error('Address was not found. Try a more specific landmark or click the map to set the point.');form.elements.latitude.value=point.lat.toFixed(7);form.elements.longitude.value=point.lng.toFixed(7);placeSafeZoneDraftMarker([point.lat,point.lng],'Detected safe zone location');safeZoneMap.setView([point.lat,point.lng],16);if(showToast)toast(matchedQuery===composeSafeZoneAddress(form)?'Latitude and longitude detected':'Nearest available location detected. Check the map pin.');}catch(error){if(showToast)toast(error.message);}finally{if(button){button.disabled=false;button.textContent='Detect latitude and longitude';}}}
function scheduleSafeZoneGeocode(){clearTimeout(safeZoneGeocodeTimer);safeZoneGeocodeTimer=setTimeout(()=>geocodeSafeZoneAddress(false),900);}
function scheduleSafeZoneAddressLookup(){clearTimeout(safeZoneAddressLookupTimer);safeZoneAddressLookupTimer=setTimeout(()=>inferSafeZoneAddressFields(false),250);}
async function initSafeZoneMap(){if(safeZoneMap){safeZoneMap.invalidateSize();if(manager)openSafeZoneForm();loadSafeZones();return;}safeZoneMap=L.map('safeZoneMap').setView(Config.MAP_CENTER,Config.MAP_ZOOM);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(safeZoneMap);safeZoneRouteLayer=L.layerGroup().addTo(safeZoneMap);safeZoneLayer=L.layerGroup().addTo(safeZoneMap);if(manager)safeZoneMap.on('click',e=>{const form=document.getElementById('safeZoneForm');form.elements.latitude.value=e.latlng.lat.toFixed(7);form.elements.longitude.value=e.latlng.lng.toFixed(7);placeSafeZoneDraftMarker(e.latlng);});if(manager&&!safeZoneMunicipalitiesLoaded){const form=document.getElementById('safeZoneForm'),select=form.elements.municipality_id;if(user.role==='subadmin'){select.add(new Option(user.municipality_name||'Assigned municipality',user.municipality_id));select.value=user.municipality_id;select.disabled=true;}else{const rows=await Api.get('/municipalities/options');rows.forEach(m=>select.add(new Option(m.municipality_name,m.id)));}select.addEventListener('change',()=>{form.elements.latitude.value='';form.elements.longitude.value='';loadSafeZoneBarangays();});form.elements.barangay?.addEventListener('change',scheduleSafeZoneGeocode);form.elements.exact_address?.addEventListener('input',scheduleSafeZoneAddressLookup);document.getElementById('safeZoneGeocodeBtn')?.addEventListener('click',async()=>{await inferSafeZoneAddressFields(false);geocodeSafeZoneAddress(true);});safeZoneMunicipalitiesLoaded=true;}if(manager)openSafeZoneForm();loadSafeZones();}
function renderSafeZones(rows,nearest=false){safeZoneLayer.clearLayers();const bounds=[];rows.forEach(s=>{const latlng=[s.latitude,s.longitude],card=safeZoneMapCard(s,false);L.marker(latlng,{icon:safeZoneIcon(nearest&&s.distance_km!==undefined?'nearest':'saved')}).bindPopup(card,{className:'safe-zone-popup',maxWidth:360,minWidth:300,autoPan:true,keepInView:true}).bindTooltip(card,{className:'safe-zone-tooltip safe-zone-tooltip-full',direction:'top',offset:[0,-42],opacity:1,interactive:true}).addTo(safeZoneLayer);bounds.push(latlng);});if(bounds.length)safeZoneMap.fitBounds(bounds,{padding:[35,35],maxZoom:15});document.getElementById('safeZonesTable').innerHTML=rows.map(s=>`<tr class="border-t"><td class="p-4"><p class="font-medium">${escapeText(s.safezone_name)}</p>${s.distance_km!==undefined?`<p class="text-xs font-semibold text-emerald-600">${s.distance_km} km away</p>`:''}</td><td class="p-4">${escapeText(s.municipality_name)}</td><td class="p-4">${escapeText(s.address)}</td><td class="p-4">${s.capacity??'-'}</td><td class="p-4 text-right"><div class="safe-zone-table-actions"><button data-action="view" data-id="${s.id}" class="safe-zone-table-action view" title="View safe zone" aria-label="View ${escapeText(s.safezone_name)}">${safeZoneActionIcon('view')}</button><button data-action="route" data-id="${s.id}" class="safe-zone-table-action route" title="Route to safe zone" aria-label="Route to ${escapeText(s.safezone_name)}">${safeZoneActionIcon('route')}</button>${manager?`<button data-action="edit" data-id="${s.id}" class="safe-zone-table-action edit" title="Edit safe zone" aria-label="Edit ${escapeText(s.safezone_name)}">${safeZoneActionIcon('edit')}</button><button data-action="delete" data-id="${s.id}" class="safe-zone-table-action delete" title="Delete safe zone" aria-label="Delete ${escapeText(s.safezone_name)}">${safeZoneActionIcon('delete')}</button>`:''}</div></td></tr>`).join('')||'<tr><td colspan="5" class="p-8 text-center text-slate-500">No safe zones found.</td></tr>';if(nearest&&rows[0])toast(`Nearest safe zone: ${rows[0].safezone_name} (${rows[0].distance_km} km)`);}
async function loadSafeZones(){try{renderSafeZones(await Api.get('/safe-zones'));}catch(e){toast(e.message);}}
function updateSafeZoneRouteSummary(html='',show=true){const panel=document.getElementById('safeZoneRouteSummary');if(!panel)return;panel.innerHTML=html;panel.classList.toggle('hidden',!show);}
function focusSafeZoneMap(){document.getElementById('safeZoneMap')?.scrollIntoView({behavior:'smooth',block:'center',inline:'nearest'});setTimeout(()=>safeZoneMap?.invalidateSize(),250);}
function drawSafeZoneRoute(start,destination,road){safeZoneRouteLayer.clearLayers();const routeColor=destination.facility_type==='evacuation_center'?'#2563eb':'#059669',line=L.geoJSON(road.geojson_data,{style:{color:'#ffffff',weight:9,opacity:.95,lineCap:'round',lineJoin:'round'}}).addTo(safeZoneRouteLayer),main=L.geoJSON(road.geojson_data,{style:{color:routeColor,weight:5,opacity:.95,lineCap:'round',lineJoin:'round'}}).addTo(safeZoneRouteLayer);L.circleMarker([start.latitude,start.longitude],{radius:9,color:'#fff',weight:3,fillColor:'#2563eb',fillOpacity:1}).bindPopup('Your current location').addTo(safeZoneRouteLayer);L.marker([destination.latitude,destination.longitude],{icon:safeZoneIcon('saved'),zIndexOffset:800}).bindPopup(safeZoneMapCard(destination,false),{className:'safe-zone-popup',maxWidth:360,minWidth:300}).addTo(safeZoneRouteLayer);safeZoneMap.fitBounds(main.getBounds().extend([start.latitude,start.longitude]).extend([destination.latitude,destination.longitude]),{padding:[55,55],maxZoom:16});}
async function routeToSafeZone(item=null){focusSafeZoneMap();const mode=safeZoneRouteMode,label=safeZoneRouteLabels[mode]||'Route';updateSafeZoneRouteSummary(`<strong>Calculating ${label.toLowerCase()}...</strong><span>Please allow location access when prompted.</span>`,true);try{const start=await currentPosition(),destination=item||((await Api.get(`/safe-zones/nearest?latitude=${start.latitude}&longitude=${start.longitude}&limit=1`))[0]);if(!destination)throw new Error('No safe zone found near your location');const road=await Api.get(`/evacuation-routes/road?mode=${mode}&start_lat=${start.latitude}&start_lng=${start.longitude}&end_lat=${destination.latitude}&end_lng=${destination.longitude}`),distance=(road.distance_m/1000).toFixed(1),duration=road.duration_s?`${Math.ceil(road.duration_s/60)} min`:'Unavailable',metricLabels=safeZoneRouteMetricLabels[road.mode]||safeZoneRouteMetricLabels[mode]||['Distance','Estimated time'],sourceText=road.source==='osrm_mode_estimate'?'Road distance with mode-based time estimate':`${safeZoneRouteLabels[road.mode]||label} estimate using mode-specific speed`;drawSafeZoneRoute(start,destination,road);focusSafeZoneMap();updateSafeZoneRouteSummary(`<div><span>${escapeText(safeZoneRouteLabels[road.mode]||label)}</span><strong>${escapeText(destination.safezone_name)}</strong></div><dl><div><dt>${metricLabels[0]}</dt><dd>${distance} km</dd></div><div><dt>${metricLabels[1]}</dt><dd>${duration}</dd></div></dl><p>${sourceText}</p>`,true);toast(`${label} ready: ${destination.safezone_name}`);}catch(error){updateSafeZoneRouteSummary(`<strong>Route unavailable</strong><span>${escapeText(error.message)}</span>`,true);toast(error.message);}}
async function openSafeZoneForm(item=null,mode='edit'){const card=document.getElementById('safeZoneFormCard'),form=document.getElementById('safeZoneForm');if(!card||!form)return;const readOnly=mode==='view';card.classList.remove('hidden');card.dataset.mode=mode;setTimeout(()=>safeZoneMap?.invalidateSize(),80);form.reset();form.querySelector('button:not([type="button"])')?.classList.remove('hidden');document.getElementById('safeZoneGeocodeBtn')?.classList.remove('hidden');['id','safezone_name','municipality_id','address','latitude','longitude','capacity','description'].forEach(k=>form.elements[k].value=item?.[k]??'');if(form.elements.exact_address)form.elements.exact_address.value=item?.address||'';if(form.elements.barangay){form.elements.barangay.innerHTML='<option value="">Select barangay</option>';form.elements.barangay.disabled=true;}if(user.role==='subadmin'){form.elements.municipality_id.value=user.municipality_id;form.elements.municipality_id.disabled=true;}if(form.elements.municipality_id.value){const rows=await loadSafeZoneBarangays();const barangay=matchSafeZoneBarangay(rows,item?.address||'');if(barangay)form.elements.barangay.value=barangay.name;}document.getElementById('safeZoneFormTitle').textContent=readOnly?'View safe zone':(item?'Edit safe zone':'Add safe zone');document.getElementById('safeZoneFormError').classList.add('hidden');[...form.elements].forEach(field=>{if(['hidden'].includes(field.type))return;if(field.tagName==='BUTTON')return;field.disabled=readOnly||(field.name==='municipality_id'&&user.role==='subadmin');field.readOnly=readOnly||['latitude','longitude'].includes(field.name);});form.querySelector('button:not([type="button"])')?.classList.toggle('hidden',readOnly);document.getElementById('safeZoneGeocodeBtn')?.classList.toggle('hidden',readOnly);card.scrollIntoView({behavior:'smooth',block:'start'});}
document.getElementById('newSafeZoneBtn')?.addEventListener('click',()=>openSafeZoneForm());
document.getElementById('safeZonesTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;try{const item=await Api.get(`/safe-zones/${button.dataset.id}`);if(button.dataset.action==='view'){await openSafeZoneForm(item,'view');L.popup({className:'safe-zone-popup',maxWidth:360,minWidth:300}).setLatLng([item.latitude,item.longitude]).setContent(safeZoneMapCard(item,false)).openOn(safeZoneMap);safeZoneMap.setView([item.latitude,item.longitude],15);}else if(button.dataset.action==='route')routeToSafeZone(item);else if(button.dataset.action==='edit')await openSafeZoneForm(item,'edit');else if(await confirmAction(`Delete ${item.safezone_name}?`)){await Api.delete(`/safe-zones/${item.id}`);toast('Safe zone deleted');loadSafeZones();overview();}}catch(err){toast(err.message);}});
document.getElementById('safeZoneForm')?.addEventListener('submit',async e=>{e.preventDefault();const error=document.getElementById('safeZoneFormError');e.target.elements.address.value=composeSafeZoneAddress(e.target);const data=Object.fromEntries(new FormData(e.target)),id=data.id;delete data.id;delete data.exact_address;delete data.barangay;if(user.role==='subadmin')data.municipality_id=user.municipality_id;error.classList.add('hidden');try{if(id)await Api.put(`/safe-zones/${id}`,data);else await Api.post('/safe-zones',data);safeZoneDraftMarker?.remove();safeZoneDraftMarker=null;toast(id?'Safe zone updated':'Safe zone added');openSafeZoneForm();loadSafeZones();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}});
function normalizeFacilityRows(safeZones=[],centers=[]){return[...safeZones.map(item=>({...item,facility_type:'safe_zone',facility_label:'Safe zone',facility_name:item.safezone_name,facility_status:item.status||'active'})),...centers.map(item=>({...item,facility_type:'evacuation_center',facility_label:'Evacuation center',facility_name:item.center_name,safezone_name:item.center_name,description:null,facility_status:item.status||'available'}))].sort((a,b)=>String(a.facility_name).localeCompare(String(b.facility_name)));}
function facilityTypeClass(type){return type==='evacuation_center'?'bg-sky-50 text-sky-700':'bg-emerald-50 text-emerald-700';}
function facilityMarkerIcon(item,nearest=false){if(nearest)return safeZoneIcon('nearest');return safeZoneIcon(item.facility_type==='evacuation_center'?'center':'saved');}
function updateSafeZoneFacilityFields(){const form=document.getElementById('safeZoneForm');if(!form?.elements.facility_type)return;const isCenter=form.elements.facility_type.value==='evacuation_center';form.querySelectorAll('[data-center-only]').forEach(el=>el.classList.toggle('hidden',!isCenter));form.querySelectorAll('[data-safezone-only]').forEach(el=>el.classList.toggle('hidden',isCenter));form.elements.description&&(form.elements.description.required=!isCenter);form.elements.contact_person&&(form.elements.contact_person.required=false);form.elements.contact_number&&(form.elements.contact_number.required=false);document.getElementById('safeZoneFormTitle').textContent=form.elements.id.value?(isCenter?'Edit evacuation center':'Edit safe zone'):(isCenter?'Add evacuation center':'Add safe zone');}
function safeZoneCardIcon(type){return type==='evacuation_center'?'<svg viewBox="0 0 48 48" aria-hidden="true"><path d="M8 21.5 24 9l16 12.5V41H8V21.5Z"/><path class="safe-zone-card-icon-cut" d="M15 23h18v5H15zM21 30h6v11h-6zM18 33h12v5H18z"/></svg>':'<svg viewBox="0 0 48 48" aria-hidden="true"><path d="M24 7 38 12v10.5C38 31 32.4 37.6 24 42 15.6 37.6 10 31 10 22.5V12l14-5Z"/><path class="safe-zone-card-icon-cut" d="M21 16h6v17h-6zM15.5 21.5h17v6h-17z"/></svg>';}
