function filteredSafeZoneRows(rows){const scoped=safeZoneFacilityFilter==='all'?rows:rows.filter(row=>row.facility_type===safeZoneFacilityFilter),term=safeZoneFacilitySearch.trim().toLowerCase();if(!term)return scoped;return scoped.filter(row=>[row.facility_name,row.facility_label,row.municipality_name,row.address,row.contact_person,row.contact_number,row.capacity].some(value=>String(value??'').toLowerCase().includes(term)));}
function updateSafeZoneFilterCounts(rows){const counts={all:rows.length,safe_zone:rows.filter(row=>row.facility_type==='safe_zone').length,evacuation_center:rows.filter(row=>row.facility_type==='evacuation_center').length};Object.entries(counts).forEach(([key,value])=>{const badge=document.querySelector(`[data-filter-count="${key}"]`);if(badge)badge.textContent=value;});}
