document.getElementById('safeZonesTable')?.addEventListener('click',async e=>{const button=e.target.closest('button[data-action]');if(!button)return;e.preventDefault();e.stopImmediatePropagation();try{const isCenter=button.dataset.kind==='evacuation_center',endpoint=isCenter?'/evacuation-centers':'/safe-zones',raw=await Api.get(`${endpoint}/${button.dataset.id}`),item={...raw,facility_type:isCenter?'evacuation_center':'safe_zone',facility_label:isCenter?'Evacuation center':'Safe zone',facility_name:isCenter?raw.center_name:raw.safezone_name,safezone_name:isCenter?raw.center_name:raw.safezone_name};if(button.dataset.action==='view'){await openSafeZoneForm(item,'view');L.popup({className:'safe-zone-popup',maxWidth:360,minWidth:300}).setLatLng([item.latitude,item.longitude]).setContent(safeZoneMapCard(item,false)).openOn(safeZoneMap);safeZoneMap.setView([item.latitude,item.longitude],15);}else if(button.dataset.action==='route')routeToSafeZone(item);else if(button.dataset.action==='edit')await openSafeZoneForm(item,'edit');else if(await confirmAction(`Delete ${item.facility_name}?`)){await Api.delete(`${endpoint}/${item.id}`);toast(isCenter?'Evacuation center deleted':'Safe zone deleted');loadSafeZones();overview();}}catch(err){toast(err.message);}},true);
document.getElementById('safeZoneForm')?.addEventListener('submit',async e=>{e.preventDefault();e.stopImmediatePropagation();const form=e.target,error=document.getElementById('safeZoneFormError'),isCenter=form.elements.facility_type.value==='evacuation_center',id=form.elements.id.value;form.elements.address.value=composeSafeZoneAddress(form);const base={municipality_id:form.elements.municipality_id.value,address:form.elements.address.value,latitude:form.elements.latitude.value,longitude:form.elements.longitude.value,capacity:form.elements.capacity.value,contact_person:form.elements.contact_person?.value||'',contact_number:form.elements.contact_number?.value||''};if(user.role==='subadmin')base.municipality_id=user.municipality_id;error.classList.add('hidden');try{if(isCenter){const payload={...base,center_name:form.elements.safezone_name.value,status:form.elements.center_status?.value||'available'};if(id)await Api.put(`/evacuation-centers/${id}`,payload);else await Api.post('/evacuation-centers',payload);}else{const payload={...base,safezone_name:form.elements.safezone_name.value,description:form.elements.description?.value||''};if(id)await Api.put(`/safe-zones/${id}`,payload);else await Api.post('/safe-zones',payload);}safeZoneDraftMarker?.remove();safeZoneDraftMarker=null;toast(id?'Facility updated':'Facility added');openSafeZoneForm();loadSafeZones();overview();}catch(err){error.textContent=err.message;error.classList.remove('hidden');}},true);
