function centerStatusMeta(status){return{available:['Available','#16a34a','Ready to receive evacuees'],full:['Full','#f97316','Capacity currently full'],under_maintenance:['Maintenance','#7c3aed','Facility under maintenance'],closed:['Closed','#64748b','Not currently operating']}[status]||[status||'Unknown','#64748b','Status not specified'];}
function centerContactDetails(c){const person=String(c.contact_person||'').trim(),number=String(c.contact_number||'').trim();if(!person&&!number)return'Not provided';return `${person?escapeText(person):'No contact person'}${number?`<br><span>${escapeText(number)}</span>`:''}`;}
function centerDetailCard(c){const [label,color,note]=centerStatusMeta(c.status),coords=`${Number(c.latitude).toFixed(4)}, ${Number(c.longitude).toFixed(4)}`,distance=c.distance_km!==undefined?`<span class="center-detail-distance">${c.distance_km} km away</span>`:'';return `<article class="center-detail-card" style="--center-color:${color}"><div class="center-detail-accent"></div><header><span class="center-detail-icon"><svg viewBox="0 0 48 48" aria-hidden="true"><path d="M8 21.5 24 9l16 12.5V41H8V21.5Z"/><path d="M15 23h18v5H15zM21 30h6v11h-6zM18 33h12v5H18z"/></svg></span><div><span class="center-detail-kicker">Evacuation center</span><h3>${escapeText(c.center_name)}</h3><p>${escapeText(c.municipality_name||'Municipality unavailable')}</p></div></header><section class="center-detail-address"><span>Address</span><p>${escapeText(c.address||'No address provided')}</p></section><div class="center-detail-status"><span>${escapeText(label)}</span><small>${escapeText(note)}</small>${distance}</div><dl><div><dt>Capacity</dt><dd>${c.capacity??'Not specified'}</dd></div><div><dt>Contact</dt><dd>${centerContactDetails(c)}</dd></div><div><dt>Coordinates</dt><dd>${coords}</dd></div></dl></article>`;}
function centerActionIcon(type){const icons={view:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M2 12s3.5-6 10-6 10 6 10 6-3.5 6-10 6S2 12 2 12Z"/><circle cx="12" cy="12" r="2.5"/></svg>',edit:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 20h4l10.5-10.5a2.1 2.1 0 0 0-3-3L5 17v3Z"/><path d="m14 7 3 3"/></svg>',delete:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 7h16M9 7V5h6v2m-8 0 1 13h8l1-13"/></svg>'};return icons[type]||'';}
function renderCenters(rows,nearest=false){centerLayer.clearLayers();const bounds=[];rows.forEach(c=>{const latlng=[c.latitude,c.longitude],color=centerStatusMeta(c.status)[1];L.circleMarker(latlng,{radius:9,color,fillColor:color,fillOpacity:.9,weight:3}).bindPopup(centerDetailCard(c),{className:'center-detail-popup',maxWidth:380,minWidth:320,autoPan:true,keepInView:true}).addTo(centerLayer);bounds.push(latlng);});if(bounds.length)centerMap.fitBounds(bounds,{padding:[35,35],maxZoom:15});document.getElementById('centersTable').innerHTML=rows.map(c=>`<tr class="border-t"><td class="p-4"><div class="center-table-name"><span class="center-table-icon"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 11 12 5l8 6v9H4v-9Z"/><path d="M8 12h8v3H8zM10 16h4v4h-4z"/></svg></span><div><p class="font-medium">${escapeText(c.center_name)}</p><p class="text-xs text-slate-500">${escapeText(c.address)}</p>${c.distance_km!==undefined?`<p class="text-xs font-semibold text-violet-600">${c.distance_km} km away</p>`:''}</div></div></td><td class="p-4">${escapeText(c.municipality_name)}</td><td class="p-4"><span class="center-status-badge center-status-${escapeText(c.status)}">${escapeText(c.status)}</span></td><td class="p-4"><span class="center-capacity-pill">${c.capacity}</span></td><td class="p-4"><div class="center-table-contact"><p class="font-medium">${escapeText(c.contact_person||'-')}</p><p class="text-xs text-slate-500">${escapeText(c.contact_number||'-')}</p></div></td><td class="p-4 text-right"><div class="center-table-actions"><button data-action="view" data-id="${c.id}" class="center-table-action view" title="View center" aria-label="View ${escapeText(c.center_name)}">${centerActionIcon('view')}</button>${manager?`<button data-action="edit" data-id="${c.id}" class="center-table-action edit" title="Edit center" aria-label="Edit ${escapeText(c.center_name)}">${centerActionIcon('edit')}</button><button data-action="delete" data-id="${c.id}" class="center-table-action delete" title="Delete center" aria-label="Delete ${escapeText(c.center_name)}">${centerActionIcon('delete')}</button>`:''}</div></td></tr>`).join('')||'<tr><td colspan="6" class="p-8 text-center text-slate-500">No evacuation centers found.</td></tr>';if(nearest&&rows[0])toast(`Nearest center: ${rows[0].center_name} (${rows[0].distance_km} km)`);}
