async function loadSavedRoutes(draw=true){try{const rows=await Api.get('/evacuation-routes');document.getElementById('routesTable').innerHTML=rows.map(r=>`<tr class="border-t"><td class="p-4 font-medium">${escapeText(r.route_name)}</td><td class="p-4">${escapeText(r.start_location.name)}</td><td class="p-4">${escapeText(r.end_location.name)}</td><td class="p-4 text-right"><button data-action="view" data-id="${r.id}" class="mr-3 text-indigo-600">Visualize</button>${manager?`<button data-action="edit" data-id="${r.id}" class="mr-3 text-amber-600">Edit</button><button data-action="delete" data-id="${r.id}" class="text-red-600">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="4" class="p-8 text-center text-slate-500">No saved routes.</td></tr>';if(draw){savedRoutesLayer.clearLayers();rows.forEach(r=>savedRoutesLayer.addData(r.geojson_data));const bounds=savedRoutesLayer.getBounds();if(bounds.isValid())routeMap.fitBounds(bounds,{padding:[35,35]});}}catch(e){showError(e.message);}}
