function renderHistoricalDisasters(rows){const money=new Intl.NumberFormat(undefined,{minimumFractionDigits:2,maximumFractionDigits:2});document.getElementById('historicalTable').innerHTML=rows.map(r=>{const title=escapeText(r.title),type=escapeText(r.disaster_type),description=escapeText(r.description||'No description'),municipality=escapeText(r.municipality_name),actions=`<div class="history-table-actions"><button data-action="view" data-id="${r.id}" class="history-table-action view" title="View record" aria-label="View ${title}">${actionIcon('view')}</button>${user.role==='admin'?`<button data-action="edit" data-id="${r.id}" class="history-table-action edit" title="Edit record" aria-label="Edit ${title}">${actionIcon('edit')}</button><button data-action="delete" data-id="${r.id}" class="history-table-action delete" title="Delete record" aria-label="Delete ${title}">${actionIcon('delete')}</button>`:''}</div>`;return `<tr class="history-row"><td class="p-4"><div class="history-record"><span class="history-record-icon">${type.slice(0,2).toUpperCase()}</span><div><strong>${title}</strong><span>${type}</span><p>${description}</p></div></div></td><td class="p-4"><span class="history-municipality">${municipality}</span></td><td class="whitespace-nowrap p-4"><time class="history-date">${escapeText(r.date_occurred)}</time></td><td class="p-4"><span class="history-number">${r.casualties}</span></td><td class="p-4"><span class="history-money">${money.format(r.damages)}</span></td><td class="whitespace-nowrap p-4 text-right">${actions}</td></tr>`;}).join('')||'<tr><td colspan="6" class="p-8 text-center text-slate-500">No historical disaster records found.</td></tr>';}
